+            2,
+        );
+        assert_eq!(c.presentation, Presentation::Emoji);
+    }
+
+    #[test]
+    fn new_sets_ltr_direction() {
+        let c = make_cluster("a", 0, 1);
+        assert_eq!(c.direction, Direction::LeftToRight);
+    }
+}

